#include <bits/stdc++.h>
using namespace std;
struct  student{
	int id,a1,a2;
	int sam(){
		return a1+a2;
	};
}s[1005];
bool d(student x){
	if(x.sam()>140&&x.a1*7+x.a2*3>=800){
		return 1;
	}else{
		return 0;
	}
}
int n;
int main(){
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>s[i].id>>s[i].a1>>s[i].a2;
		if(d(s[i])){
			cout<<"Excellent\n";
		}else{
			cout<<"Not excellent\n";
		}
	}
	return 0;
}
